import Image from "next/image";
import { useUser } from "@/providers/UserProvider";
import FetchingLoadingStatus from "@/components/FetchingLoadingStatus";


const getStatusColor = (status: string) =>
  status === "DONE"
    ? "bg-green-100 text-green-800"
    : "bg-yellow-100 text-yellow-800";

const UserManagementPage = () => {
  const { loading: getUserDetailLoading, getUserDetail } = useGetUserDetail();
  const { showNotification } = useNotification();

  const { handleEnableUser, enableUserLoading, handleDisableUser, disableUserLoading} = useUser();

  const [userData, setUserData] = useState<ApiResponseGetUserDetailType>();
  const params = useParams();
  const userID = params.userID as string;

  const fetching = useCallback(async () => {
    if (!userID) { return; }
    try {
      const user = await getUserDetail(userID);
      setUserData(user);
    } catch (error) {
      showNotification(String(error), true);
    }
  }, []);

  const didFetch = useRef<boolean>(false);
  useEffect(() => {
    if (didFetch.current) { return; }
    didFetch.current = true;
    fetching();
  }, [userID]);


  if (!userData || getUserDetailLoading) {
    return (
      <PageLoader />
    )
  }

  return (
    <div className="min-h-screen bg-gray-50 p-6">
      <div className="max-w-6xl mx-auto">
        {/* Header */}
        <div className="bg-white rounded-lg shadow-md p-6 mb-6 flex justify-between">
          <div className="flex items-center gap-4">
            <Image width={60} height={60} src={userData.avatarUrl || ""} alt="UserAvatar" className="rounded-full" />
            <div>
              <h1 className="text-3xl font-bold text-gray-800">
                {userData.firstName} {userData.lastName}
              </h1>
              <p className="text-gray-500">@{userData.username}</p>
              <span className="inline-block mt-2 px-3 py-1 bg-blue-100 text-blue-800 rounded-full text-sm font-medium">
                {userData.roleName}
              </span>
            </div>
          </div>
          <div>
            { 
              disableUserLoading ? 
                  <FetchingLoadingStatus loading={disableUserLoading} size={20} color="red"/>
              :
              !userData.deleted ? (
                <button
                  onClick={() =>  {
                    const action = async () => {
                      const success = await handleDisableUser(userData.id);
                      if (success){
                        setUserData(prev => prev ? { ...prev, deleted: true } : prev);
                      }
                    }
                    action();
                  }}
                  className="
                    flex items-center justify-center gap-2
                    px-4 py-2
                    rounded-lg
                    bg-red-500
                    text-white
                    text-sm font-medium
                    border border-red-300
                    shadow-sm
                  "
                >
                  Disabled
                </button>
              ) : (
                enableUserLoading ? 
                  <FetchingLoadingStatus loading={enableUserLoading} size={20} color="green"/>
                :
                <button
                  onClick={() =>  {
                    const action = async () => {
                      const success = await handleEnableUser(userData.id);
                      if (success){
                        setUserData(prev => prev ? { ...prev, deleted: false } : prev);
                      }
                    }
                    action();
                  }}
                  className="
                    flex items-center justify-center gap-2
                    px-4 py-2
                    rounded-lg
                    bg-green-500
                    text-white
                    text-sm font-medium
                    border border-green-300
                    shadow-sm
                  "
                >
                  Active
                </button>
              )
            }
          </div>

        </div>

        {/* User Information */}
        <div className="bg-white rounded-lg shadow-md p-6 mb-6">
          <h2 className="text-xl font-bold text-gray-800 mb-4 flex items-center gap-2">
            <User size={22} />
            User Information
          </h2>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="text-sm text-gray-600">First Name</label>
              <p className="font-medium">{userData.firstName}</p>
            </div>

            <div>
              <label className="text-sm text-gray-600">Last Name</label>
              <p className="font-medium">{userData.lastName}</p>
            </div>

            <div>
              <label className="text-sm text-gray-600 flex items-center gap-1">
                <Mail size={14} /> Email
              </label>
              <p className="font-medium">{userData.email}</p>
            </div>

            <div>
              <label className="text-sm text-gray-600 flex items-center gap-1">
                <Phone size={14} /> Phone
              </label>
              <p className="font-medium">{userData.phoneNumber}</p>
            </div>
          </div>
        </div>

        {/* Statistics */}
        <div className="bg-white rounded-lg shadow-md p-6 mb-6">
          <h2 className="text-xl font-bold mb-4 flex items-center gap-2">
            <Briefcase size={22} />
            Statistics
          </h2>

          <div className="grid grid-cols-3 gap-4">
            {Object.entries(userData.statistics).map(([key, value]) => (
              <div
                key={key}
                className="bg-blue-50 p-4 rounded-lg text-center"
              >
                <p className="text-sm text-gray-600">{key}</p>
                <p className="text-2xl font-bold text-blue-600">{value}</p>
              </div>
            ))}
          </div>
        </div>

        {/* Activities */}
        <div className="bg-white rounded-lg shadow-md p-6">
          <h2 className="text-xl font-bold mb-4 flex items-center gap-2">
            <Activity size={22} />
            Recent Activities
          </h2>

          <div className="space-y-4">
            {userData.activities.map((activity) => (
              <div
                key={activity.id}
                className="border rounded-lg p-4 hover:shadow transition"
              >
                <div className="flex justify-between">
                  <div>
                    <div className="flex items-center gap-2">
                      <h3 className="font-semibold">{activity.type}</h3>
                      <span
                        className={`px-2 py-1 text-xs rounded-full ${getStatusColor(
                          activity.status
                        )}`}
                      >
                        {activity.status}
                      </span>
                    </div>

                    <p className="text-gray-600">{activity.content}</p>

                    <div className="text-sm text-gray-500 flex gap-4 mt-2">
                      <span className="flex items-center gap-1">
                        <Briefcase size={14} />
                        {activity.leadName} - {activity.leadCompany}
                      </span>
                      <span className="flex items-center gap-1">
                        <Calendar size={14} />
                        {activity.validUntil}
                      </span>
                    </div>
                  </div>

                  {activity.completed ? (
                    <CheckCircle className="text-green-500" />
                  ) : (
                    <Clock className="text-yellow-500" />
                  )}
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
};

export default UserManagementPage;

"use client"
import React, { useEffect, useState } from 'react';
import { Search, Users, UserPlus, User } from 'lucide-react';
import PageNavigationComponent from '@/components/PageNavigationComponent';
import Image  from 'next/image';
import { useUser } from '@/providers/UserProvider';
import PageLoader from '@/components/PageLoader';
import { useRouter } from 'next/navigation';
import { CheckCircle, XCircle } from "lucide-react";

const Active = () => {
  return (
    <div className="inline-flex items-center gap-2 px-3 py-1.5 rounded-full bg-green-100 text-green-700 border border-green-200">
      <CheckCircle size={16} />
      <span className="text-sm font-medium">Active</span>
    </div>
  );
};

const Disabled = () => {
  return (
    <div className="inline-flex items-center gap-2 px-3 py-1.5 rounded-full bg-gray-100 text-gray-500 border border-gray-200">
      <XCircle size={16} />
      <span className="text-sm font-medium">Disabled</span>
    </div>
  );
};

const UserManagement = () => {
  const [currentPage, setCurrentPage] = useState<number>(1);
  // USER PROVIDER
  const { users, getListUserLoading, getUsers, getUsersWithPageNo,
         totalPage, setSearchTerm, searchTerm, handleSearchUser, userSummaryStatistic } = useUser();

  const router = useRouter();


  useEffect(() => {
    getUsers();
  }, []);

  useEffect( () => {
    const getUserPageNo = async () => {
      getUsersWithPageNo(currentPage);
    }

    getUserPageNo();
  }, [currentPage]);

  if (getListUserLoading || !userSummaryStatistic){
    return (
      <PageLoader />
    )
  }

  // Filter users based on search term

  return (
    <div className="min-h-screen bg-gray-50 p-6">
      {/* Header Stats */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8">
        {/* Total Users */}
        <div className="bg-white rounded-lg shadow p-6 flex items-center justify-between h-40">
          <div>
            <p className="text-gray-500 text-sm font-medium mb-2">Total Users</p>
            <p className="text-4xl font-bold text-gray-900">{userSummaryStatistic.totalUsers || 0}</p>
            <p className="text-green-600 text-sm mt-2">Active users</p>
          </div>
          <div className="bg-blue-100 p-4 rounded-full">
            <Users className="w-8 h-8 text-blue-600" />
          </div>
        </div>

        {/* New Users This Month */}
        <div className="bg-white rounded-lg shadow p-6 flex items-center justify-between h-40">
          <div>
            <p className="text-gray-500 text-sm font-medium mb-2">New This Month</p>
            <p className="text-4xl font-bold text-gray-900">
              {userSummaryStatistic.newThisMonth || 0}
            </p>
            <p className="text-green-600 text-sm mt-2">Recently joined</p>
          </div>
          <div className="bg-green-100 p-4 rounded-full">
            <UserPlus className="w-8 h-8 text-green-600" />
          </div>
        </div>

        {/* Active Users */}
        <div className="bg-white rounded-lg shadow p-6 flex items-center justify-between h-40">
          <div>
            <p className="text-gray-500 text-sm font-medium mb-2">Active Users</p>
            <p className="text-4xl font-bold text-gray-900">{userSummaryStatistic.activeUsers || 0}</p>
            <p className="text-blue-600 text-sm mt-2">Currently active</p>
          </div>
          <div className="bg-purple-100 p-4 rounded-full">
            <User className="w-8 h-8 text-purple-600" />
          </div>
        </div>
      </div>

      {/* Search Bar */}
      <div className="bg-white rounded-lg shadow p-4 mb-6">
        <div className="relative">
          <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400 w-5 h-5" />
          <input
            onKeyDown={(e) => {
              if (e.key === "Enter") {
                handleSearchUser(currentPage);
              }
            }}
            type="text"
            placeholder={`Search by name, email, or username...`}
            className="w-full pl-10 pr-4 py-3 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>
      </div>

      {/* User Table */}
      <div className="bg-white rounded-lg shadow overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full">
            <thead className="bg-gray-50 border-b border-gray-200">
              <tr>
                <th className="px-6 py-4 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                  User
                </th>
                <th className="px-6 py-4 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                  Username
                </th>
                <th className="px-6 py-4 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                  Email
                </th>
                <th className="px-6 py-4 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                  Phone
                </th>
                <th className="px-6 py-4 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                  STATUS
                </th>
                <th className="px-6 py-4 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                  Created At
                </th>
              </tr>
            </thead>
            <tbody className="bg-white divide-y divide-gray-200">
              {users && users.map((user) => (
                <tr 
                  onClick={() => {
                    router.push(`/users/${user.id}`)
                  }}
                  key={user.id} className="hover:bg-gray-50 transition">
                  <td className="px-6 py-4 whitespace-nowrap">
                    <div className="flex items-center">
                      <Image
                        width={10}
                        height={10}
                        src={user.avatarUrl || '/avatar.png'}
                        alt={`${user.firstName} ${user.lastName}`}
                        className="w-10 h-10 rounded-full object-cover"
                      />
                      <div className="ml-4">
                        <div className="text-sm font-medium text-gray-900">
                          {user.firstName} {user.lastName}
                        </div>
                      </div>
                    </div>
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap">
                    <div className="text-sm text-gray-900">{user.username}</div>
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap">
                    <div className="text-sm text-gray-900">{user.email}</div>
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap">
                    <div className="text-sm text-gray-900">{user.phoneNumber}</div>
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap">
                    {
                      user.deleted ? <Disabled /> : <Active />
                    }
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap">
                    <div className="text-sm text-gray-900">
                      {new Date(user.createdAt).toLocaleDateString()}
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      <PageNavigationComponent currentPage={currentPage} totalPages={totalPage} setCurrentPage={setCurrentPage} />
    </div>
  );
};

export default UserManagement;

"use client";

import Image from "next/image";
import { motion } from "framer-motion";
import {
  Mail,
  Phone,
  MapPin,
  Calendar,
  User,
  Shield,
  Edit,
  LogOut,
  Save,
  X
} from "lucide-react";
import Link from "next/link";
import useGetInfo from "@/fetching/profile/getInfo";
import { useCallback, useEffect, useState } from "react";
import PageLoader from "@/components/PageLoader";
import FetchingLoadingStatus from "@/components/FetchingLoadingStatus";
import { GetInfoResponse } from "@/lib/data.authentication";
import { useRouter } from "next/navigation";
import { useAuthentication } from "@/providers/AuthenticationProvider";
import useUpdateInfo from "@/fetching/profile/updateInfo";
import { useNotification } from "@/providers/NotificationProvider";
import { isValidEmail } from "@/util/emailValidation";
import { isValidPhoneNumber } from "@/util/phoneNumberValidation";
import UpLoadAvatar from "@/components/UpLoadAvatar";
import useUpdateInfoAvatar from "@/fetching/profile/updateInfoAvatar";


const containerVariants = {
  hidden: { opacity: 0 },
  visible: {
    opacity: 1,
    transition: { staggerChildren: 0.1 }
  }
};

const itemVariants = {
  hidden: { opacity: 0, y: 20 },
  visible: { opacity: 1, y: 0 }
};

const roleConvert = (role: string) => {
  if (role === "ADMIN") {
    return "Administrator"
  }
  if (role === "USER") {
    return "User"
  }
  return "Unidentified";
}

const Page = () => {
  const router = useRouter();

  const { loading: getInfoLoading, getInfo } = useGetInfo();
  const { loading: updateInfoLoading, updateInfo } = useUpdateInfo();
  const { loading: updateInfoAvatarLoading, updateInfoAvatar } = useUpdateInfoAvatar();


  const { showNotification } = useNotification();
  const { userInfo: info } = useAuthentication();

  const [userInfo, setUserInfo] = useState<GetInfoResponse | null>(null);
  const [isEditing, setIsEditing] = useState(false);
  const [editedData, setEditedData] = useState<any>({});
  const [hasChanges, setHasChanges] = useState(false);
  const [updateAvatar, setUpdateAvatar] = useState<string>("");
  const [avatarFile, setAvatarFile] = useState<File>();

  const getUserInfo = useCallback(async () => {
    try {
      const info = await getInfo();
      setUserInfo(info);
      setEditedData({
        firstName: info.firstName,
        lastName: info.lastName,
        email: info.email,
        phoneNumber: info.phoneNumber,
        address: info.address,
        username: info.username,
      });
      setHasChanges(false);
    } catch {
      router.push("/");
    }
  }, []);

  const checkForChanges = useCallback(() => {
    if (!userInfo) return false;

    return (
      editedData.firstName !== userInfo.firstName ||
      editedData.lastName !== userInfo.lastName ||
      editedData.email !== userInfo.email ||
      editedData.phoneNumber !== userInfo.phoneNumber ||
      editedData.address !== userInfo.address ||
      editedData.username !== userInfo.username
    );
  }, [editedData, userInfo]);

  useEffect(() => {
    getUserInfo()
  }, []);

  useEffect(() => {
    if (userInfo) {
      setHasChanges(checkForChanges());
      if (updateAvatar) {
        setHasChanges(true);
      }
    }
  }, [editedData, userInfo, checkForChanges, avatarFile, updateAvatar]);

  const handleEdit = () => {
    setIsEditing(true);
  };

  const handleCancel = () => {
    setIsEditing(false);
    setEditedData({
      firstName: userInfo?.firstName,
      lastName: userInfo?.lastName,
      email: userInfo?.email,
      phoneNumber: userInfo?.phoneNumber,
      username: userInfo?.username,
      address: userInfo?.address,
    });
    setUpdateAvatar("");
    setAvatarFile(undefined);
    setHasChanges(false);
  };

  const handleSave = async () => {
    if (!userInfo || !hasChanges) return;

    const changedData: any = {};

    if (editedData.firstName !== userInfo.firstName) changedData.firstName = editedData.firstName;
    if (editedData.lastName !== userInfo.lastName) changedData.lastName = editedData.lastName;
    if (editedData.email !== userInfo.email) changedData.email = editedData.email;
    if (editedData.phoneNumber !== userInfo.phoneNumber) changedData.phoneNumber = editedData.phoneNumber;
    if (editedData.address !== userInfo.address) changedData.address = editedData.address;
    if (editedData.username !== userInfo.username) changedData.username = editedData.username;

    if (changedData.email && !isValidEmail(changedData.email)) {
      showNotification("Your update email is not valid", true);
      return;
    }

    if (changedData.phoneNumber && !isValidPhoneNumber(changedData.phoneNumber)) {
      showNotification("Your update phone number is not valid", true);
      return;
    }

    if (avatarFile) {
      try {
        const success = await updateInfoAvatar(avatarFile);

        if (success && !changedData) {
          showNotification("Successfully update info avatar");
          return;
        }
      } catch (error) {
        showNotification(String(error), true);
      }
    }

    try {
      if (!changedData) { return; }
      const success = await updateInfo(changedData);

      if (success) {
        showNotification("Successfully update info");
        setUserInfo((prev: any) => ({
          ...prev,
          ...changedData
        }));

        setIsEditing(false);
        setHasChanges(false);
      }
    } catch (error) {
      showNotification(String(error), true);
    }
  };

  const handleInputChange = (field: string, value: string) => {
    setEditedData((prev: any) => ({
      ...prev,
      [field]: value
    }));
  };

  if (getInfoLoading && !userInfo) {
    return <PageLoader />
  }

  return (
    <div className="min-h-screen bg-[#f4f7ff] text-gray-900">
      {/* ================= HEADER ================= */}
      <header className="bg-white/80 backdrop-blur-md shadow-md flex">
        <div className="flex items-center pl-4">
          <Link
            href="/sale-report"
            className="p-2 rounded-full hover:bg-gray-100 transition duration-150 ease-in-out text-gray-600 hover:text-[#1e88e5]"
            aria-label="Go to Dashboard"
          >
            <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="size-6">
              <path strokeLinecap="round" strokeLinejoin="round" d="M15.75 9V5.25A2.25 2.25 0 0 0 13.5 3h-6a2.25 2.25 0 0 0-2.25 2.25v13.5A2.25 2.25 0 0 0 7.5 21h6a2.25 2.25 0 0 0 2.25-2.25V15M12 9l-3 3m0 0 3 3m-3-3h12.75" />
            </svg>
          </Link>
        </div>

        <div className="container mx-auto px-6 py-4 flex justify-between items-center">
          <h1 className="text-2xl font-extrabold text-[#1e88e5]">
            Vera CRM
          </h1>

          <button className="flex items-center text-gray-600 hover:text-[#1e88e5] transition">
            <LogOut className="w-5 h-5 mr-1" />
            Logout
          </button>
        </div>
      </header>

      <main className="container mx-auto px-6 py-12">
        <motion.div
          initial="hidden"
          animate="visible"
          variants={containerVariants}
          className="grid lg:grid-cols-3 gap-8"
        >
          <motion.div
            variants={itemVariants}
            className="bg-white rounded-2xl shadow-lg p-8 text-center"
          >
            <div className="flex justify-center mt-12">
              <UpLoadAvatar
                setAvatar={setUpdateAvatar}
                disabled={!isEditing}
                setAvatarFile={setAvatarFile}
                avatar={updateAvatar ? updateAvatar : userInfo?.avatarUrl || ""}
                width={80}
                height={80}
              />
            </div>

            <h2 className="text-2xl font-bold mt-4 text-gray-800">
              {userInfo?.lastName} {userInfo?.firstName}
            </h2>

            <p className="text-[#1e88e5] font-medium mt-1">
              CRM {roleConvert(info?.data?.role || "")}
            </p>

            <p className="text-gray-600 text-sm mt-4">
              Passionate about building scalable CRM systems
              and improving customer experience.
            </p>

            {!isEditing ? (
              <button
                onClick={handleEdit}
                className="mt-6 inline-flex items-center justify-center gap-2 bg-[#1e88e5] text-white px-6 py-2 rounded-full font-medium hover:bg-[#1565c0] transition shadow-md"
              >
                <Edit className="w-4 h-4" />
                Edit Profile
              </button>
            ) : (
              <div className="mt-6 flex gap-2 justify-center">
                <button
                  onClick={handleSave}
                  disabled={!hasChanges || updateInfoLoading}
                  className={`inline-flex items-center justify-center gap-2 px-6 py-2 rounded-full font-medium transition shadow-md ${hasChanges && !updateInfoLoading
                    ? "bg-green-600 text-white hover:bg-green-700"
                    : "bg-gray-300 text-gray-500 cursor-not-allowed"
                    }`}
                >
                  {updateInfoLoading ? (
                    <FetchingLoadingStatus loading={true} size={16} color="white" text="Saving..." textOpacity={1} />
                  ) : (
                    <>
                      <Save className="w-4 h-4" />
                      Save Changes
                    </>
                  )}
                </button>
                <button
                  onClick={handleCancel}
                  className="inline-flex items-center justify-center gap-2 bg-gray-500 text-white px-6 py-2 rounded-full font-medium hover:bg-gray-600 transition shadow-md"
                >
                  <X className="w-4 h-4" />
                  Cancel
                </button>
              </div>
            )}
          </motion.div>

          <motion.div
            variants={itemVariants}
            className="lg:col-span-2 space-y-8"
          >
            <div className="bg-white rounded-2xl shadow-lg p-8">
              <h3 className="text-xl font-bold text-gray-800 mb-6 flex items-center">
                <User className="w-5 h-5 mr-2 text-[#1e88e5]" />
                Personal Information
              </h3>

              <div className="grid md:grid-cols-2 gap-6 text-sm">
                {/* First Name */}
                <EditableInfoItem
                  icon={User}
                  label="First Name"
                  value={editedData.firstName}
                  isEditing={isEditing}
                  onChange={(value: any) => handleInputChange('firstName', value)}
                />

                {/* Last Name */}
                <EditableInfoItem
                  icon={User}
                  label="Last Name"
                  value={editedData.lastName}
                  isEditing={isEditing}
                  onChange={(value: any) => handleInputChange('lastName', value)}
                />

                {/* Email */}
                <EditableInfoItem
                  icon={Mail}
                  label="Email"
                  value={editedData.email || "update soon"}
                  isEditing={isEditing}
                  onChange={(value: any) => handleInputChange('email', value)}
                  type="email"
                />

                {/* Phone */}
                <EditableInfoItem
                  icon={Phone}
                  label="Phone"
                  value={editedData.phoneNumber || "update soon"}
                  isEditing={isEditing}
                  onChange={(value: any) => handleInputChange('phoneNumber', value)}
                  type="tel"
                />

                {/* Address */}
                <div className="md:col-span-2">
                  <EditableInfoItem
                    icon={MapPin}
                    label="Address"
                    value={editedData.address || "update soon"}
                    isEditing={isEditing}
                    onChange={(value: any) => handleInputChange('address', value)}
                  />
                </div>

                {/* Date of Birth - Non-editable */}
                <InfoItem icon={Calendar} label="Date of Birth" value={"update soon"} />
              </div>
            </div>

            <div className="bg-white rounded-2xl shadow-lg p-8">
              <h3 className="text-xl font-bold text-gray-800 mb-6 flex items-center">
                <Shield className="w-5 h-5 mr-2 text-[#1e88e5]" />
                Account Information
              </h3>

              <div className="grid md:grid-cols-2 gap-6 text-sm">
                <InfoItem label="Username" value={userInfo?.username} />
                <InfoItem label="Role" value={roleConvert(info?.data?.role || "")} />
                <InfoItem label="Account Status" value={userInfo?.deleted ? "Disabled" : "Active"} />
                <InfoItem label="Created At" value={userInfo?.createdAt} />
              </div>
            </div>
          </motion.div>
        </motion.div>
      </main>
    </div>
  );
};

const InfoItem = ({ icon: Icon, label, value }: any) => (
  <div className="flex items-start gap-3">
    {Icon && <Icon className="w-5 h-5 text-[#1e88e5] mt-0.5" />}
    <div>
      <p className="text-gray-500">{label}</p>
      <p className="font-medium text-gray-800">{value}</p>
    </div>
  </div>
);

const EditableInfoItem = ({
  icon: Icon,
  label,
  value,
  isEditing,
  onChange,
  type = "text"
}: any) => (
  <div className="flex items-start gap-3">
    {Icon && <Icon className="w-5 h-5 text-[#1e88e5] mt-0.5" />}
    <div className="flex-1">
      <p className="text-gray-500 mb-1">{label}</p>
      {isEditing ? (
        <input
          type={type}
          value={value}
          onChange={(e) => onChange(e.target.value)}
          className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-[#1e88e5] font-medium text-gray-800"
        />
      ) : (
        <p className="font-medium text-gray-800">{value}</p>
      )}
    </div>
  </div>
);

