"use client";

import useGetAssigners from "@/fetching/user/getAssigners";
import { useEffect, useState } from "react";
import FetchingLoadingStatus from "./FetchingLoadingStatus";
import { ApiResponseGetAssignersType } from "@/lib/data.user";
import { ChevronDown, User } from "lucide-react";

interface AssignerSelectorProps {
  value?: string;
  onChange?: (assigner: ApiResponseGetAssignersType | null) => void;
  disabled?: boolean;
}

const AssignerSelectorComponent = ({
  value,
  onChange,
  disabled = false,
}: AssignerSelectorProps) => {
  const { loading: getAssignersLoading, getAssigners } = useGetAssigners();

  const [assigners, setAssigners] = useState<ApiResponseGetAssignersType[]>([]);
  const [selectedId, setSelectedId] = useState<string>(value || "");

  useEffect(() => {
    const fetching = async () => {
      try {
        const result = await getAssigners();
        setAssigners(result);
      } catch (e) {
        console.error("Failed to fetch assigners", e);
      }
    };

    fetching();
  }, []);

  const handleChange = (id: string) => {
    setSelectedId(id);

    const selectedUser = assigners.find((u) => u.id === id) || null;
    onChange?.(selectedUser);
  };

  if (getAssignersLoading) {
    return (
      <FetchingLoadingStatus loading color="blue" size={20} />
    );
  }

  if (!assigners.length) {
    return (
      <div className="text-sm text-gray-500 italic">
        No assigners available
      </div>
    );
  }

  return (
    <div className="relative w-full">
      {/* Icon */}
      <User className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400 pointer-events-none" />

      <select
        value={selectedId}
        disabled={disabled}
        onChange={(e) => handleChange(e.target.value)}
        className={`
          w-full appearance-none rounded-lg border px-10 py-2.5 text-sm
          bg-white shadow-sm transition
          focus:outline-none focus:ring-2 focus:ring-blue-500
          ${disabled ? "bg-gray-100 cursor-not-allowed" : "hover:border-gray-400"}
        `}
      >
        <option value="" disabled>
          Select an assigner
        </option>

        {assigners.map((user) => (
          <option key={user.id} value={user.id}>
            {user.fullName}
          </option>
        ))}
      </select>

      {/* Dropdown Icon */}
      <ChevronDown className="absolute right-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400 pointer-events-none" />
    </div>
  );
};

export default AssignerSelectorComponent;

"use client";

import {
  ApiResponseDataLeadActivity,
  LeadDetailActivityTimeline,
  LeadDetailType,
  RequestAddNewLeadActivity
} from "@/lib/data.leads";
import { createContext, useCallback, useContext, useState, useEffect } from "react";
import { useNotification } from "./NotificationProvider";
import useGetLeadDetail from "@/fetching/lead/getLeadDetail";
import useUpdateLeadStage from "@/fetching/lead/updateLeadStage";
import useUpdateLeadDetail from "@/fetching/lead/updateLeadDetail";
import { useLeadStageColumn } from "./LeadStageColumnProvider";
import useAddLeadActivity from "@/fetching/lead/addLeadActivity";
import useCompleteActivity from "@/fetching/lead/completeActivity";
import useDeleteActivity from "@/fetching/lead/deleteActivity";
import { isValidPhoneNumber } from "@/util/phoneNumberValidation";
import { isValidEmail } from "@/util/emailValidation";

interface LeadDetailSelectContextType {
  selectedLeadId: string | null;
  leadDetailInfo: LeadDetailType | null;
  leadSequenceActivity: ApiResponseDataLeadActivity[] | null;
  loadingGetLeadDetail: boolean;
  loadingCompleteLeadActivity: boolean;
  loadingDeleteActivity: boolean,
  selectLeadDetail: (leadID: string) => void;
  removeSelectedLeadDetail: () => void;
  addingNewLeadActivity: (newLead: RequestAddNewLeadActivity) => void;
  updateALeadDetail: (newLeadDetail: LeadDetailType, avatarFile: File | undefined) => void;
  updateLeadStage: (leadID: string, forwardStageID: string) => void;
  completeLeadActivity: (activityID: string) => void;
  deleteLeadActivity: (activityID: string) => void;
}

const LeadDetailSelectContext = createContext<LeadDetailSelectContextType | null>(null);

export const useLeadDetailSelect = () => {
  const context = useContext(LeadDetailSelectContext);
  if (!context) {
    throw new Error("useLeadDetailSelect must be used within LeadDetailSelectProvider");
  }
  return context;
};

interface LeadDetailSelectProviderProps {
  children: React.ReactNode;
}

export const LeadDetailSelectProvider = ({ children }: LeadDetailSelectProviderProps) => {
  const [listLeadDetail, setListLeadDetail] = useState<Record<string, LeadDetailType>>({});
  const [selectedLeadId, setSelectedLeadId] = useState<string | null>(null);
  const [leadDetailInfo, setLeadDetailInfo] = useState<LeadDetailType | null>(null);
  const [leadSequenceActivity, setLeadSequenceActivity] = useState<ApiResponseDataLeadActivity[] | null>(null);
  const { showNotification } = useNotification();

  const { loading: loadingUpdateLeadDetail, updateLeadDetail } = useUpdateLeadDetail();
  const { loading: loadingGetLeadDetail, getLeadDetailInformation } = useGetLeadDetail();
  const { loading: loadingUpdateLeadStage, updateLeadStage: updateStage } = useUpdateLeadStage();
  const { loading: loadingAddLeadActivity, addLeadActivity } = useAddLeadActivity();
  const { loading: loadingCompleteLeadActivity, completeActivity } = useCompleteActivity();
  const { loading: loadingDeleteActivity, deleteActivity } = useDeleteActivity();
  // HANDLE CLICK ON A LEAD
  const selectLeadDetail = (leadID: string) => {
    setSelectedLeadId(leadID);
  };

  // HANDLE CLOSE LEAD DETAIL
  const removeSelectedLeadDetail = () => {
    setSelectedLeadId(null);
    setLeadDetailInfo(null);
    setLeadSequenceActivity(null);
  };

  // ASYNC FETCH LEAD DETAIL WHEN selectedLeadId CHANGES
  const fetchLeadDetail = useCallback(async (leadID: string) => {
    if (!leadID) return;

    try {
      const { leadDetail, leadActivity } = await getLeadDetailInformation(leadID);

      if (!leadDetail) return;

      setLeadDetailInfo(leadDetail);

      // // Map sequence activities from local sample or API if exists
      const sequenceActivity: ApiResponseDataLeadActivity[] = leadActivity || [];
      setLeadSequenceActivity(sequenceActivity);

    } catch (err) {
      showNotification("Failed to get lead detail", true);
    }
  }, [getLeadDetailInformation, showNotification]);

  useEffect(() => {
    if (selectedLeadId) {
      fetchLeadDetail(selectedLeadId);
    } else {
      setLeadDetailInfo(null);
      setLeadSequenceActivity(null);
    }
  }, [selectedLeadId]);

  // ADD NEW LEAD ACTIVITY
  const addingNewLeadActivity = async (newLeadActivity: RequestAddNewLeadActivity) => {
    try {
      if (!selectedLeadId) { return; }

      const response = await addLeadActivity(selectedLeadId, newLeadActivity);

      if (response && response.code === 200) {
        setLeadSequenceActivity(prev => {
          if (!prev) return prev;
          return [response.data, ...prev];
        });
        showNotification("Successfully added a new lead activity");
      }
    } catch (error) {
      showNotification(String(error), true);
    }
  };


  // UPDATE LEAD DETAIL
  const { syncLeadDetail } = useLeadStageColumn();

  const updateALeadDetail = async (newLeadDetail: LeadDetailType, avatarFile: File | undefined) => {
    try {
      if (
        (newLeadDetail.phone?.length && !isValidPhoneNumber(newLeadDetail.phone))
        ||
        (newLeadDetail.email?.length && !isValidEmail(newLeadDetail.email))
      ) {
        showNotification("Your update phone number or email is not valid", true);
        return;
      }


      const { resData, updatedLead } =
        await updateLeadDetail(newLeadDetail, avatarFile);

      if (resData.code === 200) {
        setLeadDetailInfo(updatedLead);
        syncLeadDetail(updatedLead);
        showNotification("Lead updated successfully");
      }
    } catch (err) {
      showNotification(String(err), true);
    }
  };


  // UPDATE LEAD STAGE 
  const { syncLeadStage } = useLeadStageColumn();

  const updateLeadStage = async (leadID: string, forwardStageID: string) => {
    try {
      const success = await updateStage(leadID, forwardStageID);

      if (success) {
        syncLeadStage(leadID, forwardStageID);
        showNotification("Lead stage updated");
      }
    } catch (err) {
      showNotification(String(err), true);
    }
  };

  // COMPLETE LEAD ACTIVITY
  const completeLeadActivity = async (activityID: string) => {
    try {
      if (!selectedLeadId) return;

      const success = await completeActivity(selectedLeadId, activityID);

      if (!success) {
        showNotification("There is error in complete an activity", true);
        return;
      }

      showNotification("Successfully complete an activity");

      setLeadSequenceActivity(prev => {
        if (!prev) return prev;

        const index = prev.findIndex(item => item.id === activityID);
        if (index === -1) {
          showNotification(
            "There is error in async with UI when complete an activity",
            true
          );
          return prev;
        }

        const newList = [...prev];
        newList[index] = {
          ...newList[index],
          status: "DONE",
          completed: true,
        };

        return newList;
      });

    } catch (err) {
      showNotification(String(err), true);
    }
  };

  const deleteLeadActivity = async (activityID: string) => {
    try {
      if (!selectedLeadId) return;

      const success = await deleteActivity(selectedLeadId, activityID);

      if (!success) {
        showNotification("There is error in delete an activity", true);
        return;
      }

      showNotification("Successfully delete an activity");

      setLeadSequenceActivity(prev => {
        if (!prev) return prev;

        const newList = prev.filter(item => item.id !== activityID);

        return newList
      });

    } catch (err) {
      showNotification(String(err), true);
    }
  }



  const value: LeadDetailSelectContextType = {
    selectedLeadId,
    leadDetailInfo,
    leadSequenceActivity,
    loadingGetLeadDetail,
    loadingCompleteLeadActivity,
    loadingDeleteActivity,
    selectLeadDetail,
    removeSelectedLeadDetail,
    addingNewLeadActivity,
    updateALeadDetail,
    updateLeadStage,
    completeLeadActivity,
    deleteLeadActivity,
  };

  return (
    <LeadDetailSelectContext.Provider value={value}>
      {children}
    </LeadDetailSelectContext.Provider>
  );
};

"use client";

import React, { createContext, useContext, useState, ReactNode, useEffect, useCallback, useRef } from "react";
import { leadType, leadStageType, LeadDetailType } from "@/lib/data.leads";
import useGetListLeads from "@/fetching/lead/getListLeads";
import useAddLead from "@/fetching/lead/addLead";
import { useNotification } from "./NotificationProvider";
import useDeleteLead from "@/fetching/lead/deleteLead";
import useUpdateLeadStage from "@/fetching/lead/updateLeadStage";
import useAddStage from "@/fetching/stage/addStage";
import useDeleteStage from "@/fetching/stage/deleteStage";
import useSearchLead from "@/fetching/lead/searchLead";

// CONTEXT VALUE TYPE
interface LeadStageColumnContextType {
  leadStage: leadStageType[],
  isInitialLoading: boolean,
  getListLeadLoading: boolean,
  addLeadLoading: boolean,
  deleteLeadLoading: boolean,
  updateDropStageLoading: boolean,
  addStageLoading: boolean,
  deleteStageLoading: boolean,
  searchLeadLoading: boolean,
  leadItemsInStage: Record<string, leadType[]>,
  updateLeadStage: (leadId: string, newStage: string) => void,
  addingNewLead: (newLead: leadType, targetColumn: string, stageID: string) => void,
  addingNewLeadColum: (columnName: string, columnColor: string) => void,
  deleteALead: (leadID: string) => void,
  syncLeadDetail: (lead: LeadDetailType) => void;
  syncLeadStage: (leadID: string, stage: string) => void;
  deleteLeadColumn: (stageID: string) => void;
  searchLead: (query: string) => void;
}

// CREATE CONTEXT
const LeadStageColumnContext = createContext<LeadStageColumnContextType | null>(null);

// CUSTOM HOOK
export const useLeadStageColumn = () => {
  const context = useContext(LeadStageColumnContext);
  if (!context) {
    throw new Error("useLeadStageColumn must be used within LeadStageColumnProvider");
  }
  return context;
};

// PROVIDER PROPS
interface LeadStageColumnProviderProps {
  children: ReactNode;
}

export const LeadStageColumnProvider: React.FC<LeadStageColumnProviderProps> = ({ children }) => {
  const { showNotification } = useNotification();
  // INITIALIZE GET LIST LEADS REQUEST
  const { loading: deleteLeadLoading, deleteLead } = useDeleteLead();
  const { loading: getListLeadLoading, requestGetListLeads } = useGetListLeads();
  const { loading: addLeadLoading, addLead } = useAddLead();
  const { loading: updateDropStageLoading, updateLeadStage: fetchUpdateLeadStage } = useUpdateLeadStage();
  const { loading: addStageLoading, addStage } = useAddStage();
  const { loading: deleteStageLoading, deleteStage } = useDeleteStage();
  const { loading: searchLeadLoading, searchListLead } = useSearchLead();
  // LEAD ITEMS IN SPECIFIC COLUMN INITIALIZE
  const [leadItemsInStage, setLeadItemsInStage] = useState<Record<string, leadType[]>>({});
  const [leadStage, setLeadStage] = useState<leadStageType[]>([]);
  const [isInitialLoading, setIsInitialLoading] = useState<boolean>(true);

  // GET LIST LEAD REQUEST
  const getListLeads = useCallback(async () => {
    try {
      setIsInitialLoading(true);
      const { data, leadStage } = await requestGetListLeads();

      if (!data || !leadStage) {
        setLeadStage([]);
        setLeadItemsInStage({});
        return;
      }

      setLeadStage(leadStage);

      const initial: Record<string, leadType[]> = {};

      leadStage.forEach((stageColumn) => {
        const stageData = data.find(item => item.id === stageColumn.id);

        const leadsInThisStage: leadType[] = stageData?.leads.map((item) => ({
          leadID: item.id,
          avatarURL: item.avatarUrl || "",
          name: item.fullName,
          createdDate: item.createdAt,
          phone: item.phoneNumber || "",
          email: item.email || "",
          rating: item.rating ?? 0,
          source: item.source || "Facebook",
          status: stageColumn.status,
          expectedRevenue: item.expectedRevenue,
        })) ?? [];

        initial[stageColumn.status] = leadsInThisStage;
      });

      setLeadItemsInStage(initial);
    } catch (err) {
      console.error("Error fetching leads:", err);
      setLeadItemsInStage({});
      setLeadStage([]);
    } finally {
      setIsInitialLoading(false);
    }
  }, [requestGetListLeads]);

  const didFetch = useRef(false);

  useEffect(() => {
    if (!didFetch.current) {
      getListLeads();
      didFetch.current = true;
    }
  }, []);

  // UPDATE LEAD IN STAGE WHEN DRAG AND DROP
  const updateLeadStage = async (leadId: string, newStage: string) => {
    let forwardStageID = leadStage.find(stage => stage.status === newStage)?.id || "";

    const currentStage = Object.keys(leadItemsInStage).find(stage =>
      leadItemsInStage[stage].some(lead => lead.leadID === leadId)
    ) || "";

    if (!currentStage) {
      showNotification("Current stage not found", true);
      return;
    }

    if (currentStage === newStage) {
      showNotification("The same stage");
      return;
    }

    if (!forwardStageID) {
      showNotification("The forward stage does not exist", true);
      return;
    }
    try {
      const response = await fetchUpdateLeadStage(leadId, forwardStageID);

      if (response) {
        showNotification("Successfully stage change");
        setLeadItemsInStage((prev) => {
          let leadToMove: leadType | undefined = undefined;
          let fromStage: string | null = null;

          for (const stage in prev) {
            const index = prev[stage].findIndex((item) => item.leadID === leadId);
            if (index !== -1) {
              leadToMove = prev[stage][index];
              fromStage = stage;
              break;
            }
          }

          if (!leadToMove || !fromStage || fromStage === newStage) {
            return prev;
          }

          const newColumns: Record<string, leadType[]> = { ...prev };

          newColumns[fromStage] = prev[fromStage].filter((item) => item.leadID !== leadId);

          newColumns[newStage] = [
            ...(prev[newStage] || []),
            { ...leadToMove, status: newStage }
          ];

          return newColumns;
        });
      } else {
        showNotification("There is error in drag drop stage changing", true);
      }
    } catch (err) {
      showNotification(String(err), true);
    }
  };

  // ADDING A NEW LEAD 
  const addingNewLead = async (newLead: leadType, targetColumn: string, stageID: string) => {
    try {
      const response = await addLead(newLead, stageID);

      if (!response) {
        showNotification("Failed to add lead", true);
        return false;
      }

      const lead: leadType = {
        leadID: response.id,
        avatarURL: response.avatarUrl,
        name: response.fullName,
        createdDate: response.createdAt,
        phone: response.phoneNumber,
        email: response.email,
        rating: response.rating,
        expectedRevenue: response.expectedRevenue,
        source: response.source,
        status: response.stage.name,
      }

      setLeadItemsInStage((prev) => ({
        ...prev,
        [targetColumn]: [...prev[targetColumn], lead]
      }));
      showNotification("Successfully add a new lead");
      return true;
    } catch (err) {
      showNotification(String(err), true);
    }
  }

  // DELETE A LEAD
  const deleteALead = async (leadID: string) => {
    try {
      const success: boolean = await deleteLead(leadID);

      if (success) {
        setLeadItemsInStage(prev => {
          const newLead: Record<string, leadType[]> = prev;
          for (const stage in newLead) {
            newLead[stage] = newLead[stage].filter((item) => item.leadID !== leadID)
          }

          return newLead;
        })
        showNotification("Successfully delete a lead")
      } else {
        showNotification("There is error in delete lead", true);
      }
    } catch (err) {
      showNotification(String(err), true);
    }
  }

  // SEARCH LEAD
  const searchLead = async (query: string) => {
    try {
      const { data, leadStage } = await searchListLead(query);

      if (!data || !leadStage) {
        setLeadStage([]);
        setLeadItemsInStage({});
        return;
      }

      setLeadStage(leadStage);

      const initial: Record<string, leadType[]> = {};

      leadStage.forEach((stageColumn) => {
        const stageData = data.find(item => item.id === stageColumn.id);

        const leadsInThisStage: leadType[] = stageData?.leads.map((item) => ({
          leadID: item.id,
          avatarURL: item.avatarUrl || "",
          name: item.fullName,
          createdDate: item.createdAt,
          phone: item.phoneNumber || "",
          email: item.email || "",
          rating: item.rating ?? 0,
          source: item.source || "Facebook",
          status: stageColumn.status,
          expectedRevenue: item.expectedRevenue,
        })) ?? [];

        initial[stageColumn.status] = leadsInThisStage;
      });

      setLeadItemsInStage(initial);
    } catch (err) {
      console.error("Error fetching leads:", err);
      setLeadItemsInStage({});
      setLeadStage([]);
    }
  }

  // ADDING NEW STAGE COLUMN 
  const addingNewLeadColum = async (columnName: string, columnColor: string) => {
    if (!columnName.trim()) {
      showNotification("Fill in column name", true);
      return;
    }

    try {
      const response = await addStage(columnName, columnColor);

      if (!response || response.code !== 200) {
        showNotification("There is error in add a new stage", true);
        return;
      }

      const newStage = response.data;

      setLeadStage((prev) => {
        const lostIndex = prev.findIndex(stage => stage.status === "Lost");
        const wonIndex = prev.findIndex(stage => stage.status === "Won");

        const newStageItem = {
          id: newStage.id,
          status: newStage.name,
          color: newStage.color,
        };

        if (lostIndex === -1 || wonIndex === -1) {
          return [...prev, newStageItem];
        }

        const filtered = prev.filter(
          s => s.status !== "Lost" && s.status !== "Won"
        );

        return [
          ...filtered,
          newStageItem,
          prev[lostIndex],
          prev[wonIndex],
        ];
      });

      setLeadItemsInStage((prev) => ({
        ...prev,
        [newStage.status]: [],
      }));

      showNotification("Successfully add a new stage");

    } catch (error) {
      showNotification(String(error), true);
    }
  };

  // DELETE A STAGE COLUMN
  const deleteLeadColumn = async (stageID: string) => {
    try {
      const success = await deleteStage(stageID);

      if (success) {
        showNotification("Delete stage successfully");
        setLeadStage(prev => {
          const newLeadStage = prev.filter(stage => stage.id !== stageID);
          return newLeadStage;
        })
      } else {
        showNotification("There is errror in delete a stage", true)
      }
    } catch (error) {
      showNotification(String(error), true);
    }
  }

  // MAKE ASYNC WHEN UPDATE LEAD DETAIL 
  const syncLeadDetail = (updatedLead: LeadDetailType) => {
    setLeadItemsInStage(prev => {
      const newStage = updatedLead.status;
      if (!newStage) return prev;

      const newColumns = { ...prev };

      for (const stage in prev) {
        newColumns[stage] = prev[stage].map(lead =>
          lead.leadID === updatedLead.leadID
            ? {
              ...lead,
              avatarURL: updatedLead.avatarURL,
              name: updatedLead.name,
              phone: updatedLead.phone,
              email: updatedLead.email,
              rating: updatedLead.rating,
              expectedRevenue: updatedLead.expectedValue,
            }
            : lead
        );
      }

      return newColumns;
    });
  };

  // MAKE ASYNC WHEN LEAD STAGE CHANGE
  const syncLeadStage = (leadID: string, forwardStageID: string) => {
    setLeadItemsInStage(prev => {
      let movingLead: leadType | null = null;
      let fromStage: string | null = null;

      const stageObj = leadStage.find(stage => stage.id === forwardStageID);
      const newStage = stageObj?.status;

      if (!newStage) return prev;

      for (const stage in prev) {
        const found = prev[stage].find(l => l.leadID === leadID);
        if (found) {
          movingLead = found;
          movingLead.status = newStage;
          fromStage = stage;
          break;
        }
      }

      if (!movingLead || !fromStage || fromStage === newStage) {
        return prev;
      }

      return {
        ...prev,
        [fromStage]: prev[fromStage].filter(l => l.leadID !== leadID),
        [newStage]: [
          ...(prev[newStage] || []),
          { ...movingLead, status: newStage }
        ],
      };
    });
  };



  return (
    <LeadStageColumnContext.Provider value={{
      isInitialLoading,
      getListLeadLoading,
      addLeadLoading,
      deleteLeadLoading,
      deleteStageLoading,
      updateDropStageLoading,
      searchLeadLoading,
      addStageLoading,
      leadStage,
      leadItemsInStage,
      updateLeadStage,
      addingNewLead,
      addingNewLeadColum,
      deleteALead,
      syncLeadDetail,
      syncLeadStage,
      deleteLeadColumn,
      searchLead,
    }}>
      {children}
    </LeadStageColumnContext.Provider>
  );
};

"use client"

import useGetListUser from "@/fetching/user/getListUsers";
import useSearchUsers from "@/fetching/user/searchUsers";
import { ApiResponseGetUserSummary, GetListUserResponseType } from "@/lib/data.user";
import { createContext, ReactNode, useCallback, useContext, useEffect, useRef, useState } from "react"
import { useNotification } from "./NotificationProvider";
import useUserSummary from "@/fetching/user/userSummary";
import useEnableUser from "@/fetching/user/enableUser";
import useDisableUser from "@/fetching/user/disabledUser";

interface UserProviderContextType {
  // LOADING 
  getListUserLoading: boolean,
  enableUserLoading: boolean,
  disableUserLoading: boolean,

  // STATE
  users: GetListUserResponseType[] | null,
  totalPage: number,
  setSearchTerm: React.Dispatch<React.SetStateAction<string>>,
  searchTerm: string,
  userSummaryStatistic: ApiResponseGetUserSummary | undefined,

  // FUNCTION 
  getUsers: () => void,
  getUsersWithPageNo: (pageNo: number) => void,
  handleSearchUser: (pageNo: number) => void,
  handleEnableUser: (userID: string) => Promise<boolean>,
  handleDisableUser: (userID: string) => Promise<boolean>,
};

const UserContext = createContext<UserProviderContextType | null>(null);


export const useUser = () => {
  const context = useContext(UserContext);
  if (!context) {
    throw new Error("useUser must be used within UserProvider");
  }

  return context;
}

interface UserProviderProps {
  children: ReactNode,
}

export const UserProvider: React.FC<UserProviderProps> = ({ children }) => {
  const { showNotification } = useNotification();

  // STATE 
  const [users, setUsers] = useState<GetListUserResponseType[] | null>(null);
  const [totalPage, setTotalPage] = useState<number>(1);
  const [searchTerm, setSearchTerm] = useState<string>("");
  const [userSummaryStatistic, setUserSummaryStatistic] = useState<ApiResponseGetUserSummary>();

  // API HOOK
  const { loading: getListUserLoading, getListUser } = useGetListUser();
  const { loading: searchUserLoading, searchUsers } = useSearchUsers();
  const { loading: getUserSummaryLoading, userSummary } = useUserSummary();
  const { loading: enableUserLoading, enableUser } = useEnableUser();
  const { loading: disableUserLoading, disableUser } = useDisableUser();

  /**
   * get users - initialize to take all users from backend, and then set to 'users' state
   */
  const getUsers = useCallback(async () => {
    try {
      const [listResult, userStatistic] = await Promise.all([
        getListUser(1),
        userSummary()
      ]);
      const { users, pagination } = listResult;

      setUserSummaryStatistic(userStatistic);
      setTotalPage(pagination.totalPages);
      setUsers(users || []);
    } catch (error) {
      console.error("Failed to fetch users:", error);
      setUsers([]);
    }
  }, []);
  const didFetch = useRef<boolean>(false);
  useEffect(() => {
    if (didFetch.current) { return; }
    didFetch.current = true;
    getUsers();
  }, []);

  /**
   * get users with page number - handle the action when user want to change page to view more user
   * @param pageNo current pgae number
   */
  const getUsersWithPageNo = async (pageNo: number) => {
    if (searchTerm) { handleSearchUser(pageNo); return; }
    try {
      const { users, pagination } = await getListUser(pageNo);
      setUsers(users || []);
    } catch (error) {
      console.error("Failed to fetch users:", error);
      setUsers([]);
    }
  }

  const handleSearchUser = async (pageNo: number) => {
    try {
      const { users, pagination } = await searchUsers(searchTerm, pageNo);

      if (users.length !== 0) {
        setTotalPage(pagination.totalPages);
        setUsers(users || []);
      }
    } catch (error) {
      showNotification(String(error) || "Processed failed", true);
    }
  }

  const handleEnableUser = async (userID: string): Promise<boolean> => {
    try {
      const success = await enableUser(userID);

      if (success) {
        showNotification("Successfully enable user");
        return true;
      }

      return false;
    } catch (error) {
      showNotification(String(error) || "Processed failed", true);
      return false;
    }
  }

  const handleDisableUser = async (userID: string): Promise<boolean> => {
    try {
      const success = await disableUser(userID);

      if (success) {
        showNotification("Successfully enable user");
        return true;
      }

      return false;
    } catch (error) {
      showNotification(String(error) || "Processed failed", true);
      return false;
    }
  }


  const value: UserProviderContextType = {
    getListUserLoading,
    enableUserLoading,
    disableUserLoading,

    users,
    totalPage,
    setSearchTerm,
    searchTerm,
    userSummaryStatistic,

    getUsers,
    getUsersWithPageNo,
    handleSearchUser,
    handleEnableUser,
    handleDisableUser,
  }
  return (
    <UserContext.Provider value={value}>
      {children}
    </UserContext.Provider>
  )
}

import { createContext, ReactNode, useContext, useEffect, useState } from "react";
import Papa from 'papaparse';
import useUploadCSV from "@/fetching/lead/uploadCSV";
import { useNotification } from "../NotificationProvider";

interface LeadUploadCSVContextType {
  // API HOOKS
  uploadCSVLoading: boolean,
  // STATE
  fileRow: Record<string, string[]> | null,

  // AcTIONS 
  handleUploadCSV: (leadInCSV: File) => void,
  cancelUploadFile: () => void,
  confirmUploadFile: (matching: Record<string, string>) => void,
}

const LeadUploadCSVcontext = createContext<LeadUploadCSVContextType | null>(null);

export const useLeadUploadCSV = () => {
  const context = useContext(LeadUploadCSVcontext);
  if (!context) {
    throw new Error("useLeadUploadCSV must be used within LeadUploadCSVProvider");
  }

  return context;
}

interface useLeadUploadCSVProviderProps {
  children: ReactNode
}
/**
 * Lead upload by CSV - handle all action relates with upload lead by csv
 */
export const LeadUploadCSVProvider = ({ children }: useLeadUploadCSVProviderProps) => {
  // API HOOKS
  const { loading: uploadCSVLoading, uploadCSV } = useUploadCSV();

  // STATE
  const [uploadFile, setUploadFile] = useState<File | null>(null);
  const [fileRow, setFileRow] = useState<Record<string, string[]> | null>(null)
  const { showNotification, showNotificationLeadCSV } = useNotification();

  /**
   * set the file csv of user to selected CSV file
   * @param leadInCSV leads in CSV
   */
  const handleUploadCSV = (leadInCSV: File) => {
    setUploadFile(leadInCSV);
  }

  /**
   * complie the header of upload lead file to string array
   * @returns headers of file (string datatype)
   */
  const compileFileHeader = () => {
    if (uploadFile) {
      Papa.parse(uploadFile, {
        header: false,
        skipEmptyLines: true,
        complete: (results) => {
          if (results.data && results.data.length > 0) {
            const firstRow = results.data[0] as string[];
            const secondRow = results.data[1] as string[];
            const data = {
              "headers": firstRow,
              "secondRow": secondRow,
            }

            setFileRow(data);
          }
        }
      });
    }
  }

  /**
   * confirm upload lead file - take action to send to server 
   * @param matching user's file header and business property matching
   */
  const confirmUploadFile = async (matching: Record<string, string>) => {

    if (!uploadFile) {
      showNotification("Cannot read file", true);
      return;
    }

    const response = await uploadCSV(matching, uploadFile);

    if (response.code !== 200) {
      const msg =
        typeof response.error === "object"
          ? response.error.message || "Upload failed"
          : "Upload failed";

      showNotification(msg, true);
      return;
    }

    if (response.error?.length !== 0){
      showNotificationLeadCSV(response.error);
      resetAllState();
      return;
    }

    resetAllState();
    showNotification("Successfully import leads by CSV");
  };


  /**
   * cancel upload leads by CSV - reset all fields into null
   */
  const cancelUploadFile = () => {
    setUploadFile(null);
    setFileRow(null)
  }

  /**
   * reset uplaod leads upload by CSV state - reset all fields into null whenever successful
   */
  const resetAllState = () => {
    setUploadFile(null);
    setFileRow(null);
  }

  /**
   * Initialize action - whenever have the upload file CSV (leads)
   */
  useEffect(() => {
    compileFileHeader();
  }, [uploadFile]);


  const value: LeadUploadCSVContextType = {
    // API HOOK
    uploadCSVLoading,
    // STATE
    fileRow,


    // ACTIOn
    handleUploadCSV,
    cancelUploadFile,
    confirmUploadFile
  }
  return (
    <LeadUploadCSVcontext.Provider value={value}>
      {children}
    </LeadUploadCSVcontext.Provider>
  )
}
